@RestController
@RequestMapping("/orders")
class OrderController {

    private final OrderService orderService;

    OrderController(OrderService orderService) {
        this.orderService = orderService;
    }

    @GetMapping("/{orderId}")
    public ResponseEntity<OrderResponse> getOrderById(@PathVariable String orderId) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth == null || auth.getName() == null || auth.getName().isBlank()) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "Unauthorized");
        }

        String userId = auth.getName();
        OrderResponse response = orderService.getOrderForUser(orderId, userId);
        return ResponseEntity.ok(response);
    }
}

@Service
class OrderService {

    private final OrderRepository orderRepository;

    OrderService(OrderRepository orderRepository) {
        this.orderRepository = orderRepository;
    }

    public OrderResponse getOrderForUser(String orderId, String userId) {
        Order order = orderRepository.findById(orderId)
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "Order not found"));

        if (!Objects.equals(order.userId(), userId)) {
            throw new ResponseStatusException(HttpStatus.FORBIDDEN, "Forbidden");
        }

        BigDecimal total = order.items().stream()
                .map(i -> i.unitPrice().multiply(BigDecimal.valueOf(i.quantity())))
                .reduce(BigDecimal.ZERO, BigDecimal::add);

        List<OrderItemResponse> items = new ArrayList<>();
        for (OrderItem item : order.items()) {
            BigDecimal lineTotal = item.unitPrice().multiply(BigDecimal.valueOf(item.quantity()));
            items.add(new OrderItemResponse(item.sku(), item.name(), item.quantity(), item.unitPrice(), lineTotal));
        }

        return new OrderResponse(order.id(), order.createdAt(), items, total);
    }
}

interface OrderRepository {
    Optional<Order> findById(String orderId);
    void save(Order order);
}

@Repository
class InMemoryOrderRepository implements OrderRepository {
    private final Map<String, Order> storage = new ConcurrentHashMap<>();

    @Override
    public Optional<Order> findById(String orderId) {
        return Optional.ofNullable(storage.get(orderId));
    }

    @Override
    public void save(Order order) {
        storage.put(order.id(), order);
    }
}

record Order(String id, String userId, Instant createdAt, List<OrderItem> items) { }

record OrderItem(String sku, String name, int quantity, BigDecimal unitPrice) { }

record OrderResponse(String orderId, Instant createdAt, List<OrderItemResponse> items, BigDecimal total) { }

record OrderItemResponse(String sku, String name, int quantity, BigDecimal unitPrice, BigDecimal lineTotal) { }